// ============================================================
//  SLIDESHOW ENGINE
//  Works automatically for every project card.
//  No changes needed here when adding new projects.
// ============================================================

// Inject the embedded screenshot data
// (these are set from the Python build step — see comments below
//  if you want to swap to URL-based images instead)
const SLIDE_DATA = {
  'talentscreenai': [
    'data:image/png;base64,',
    'data:image/png;base64,',
    'data:image/png;base64,',
    'data:image/png;base64,',
    'data:image/png;base64,'
  ]
};

// ── Inject base64 sources into slide <img> elements ──
document.querySelectorAll('.project-card').forEach(card => {
  const id = card.id.replace('card-', '');
  const slides = card.querySelectorAll('.slide img');
  const data = SLIDE_DATA[id];
  if (data) {
    slides.forEach((img, i) => {
      if (data[i]) img.src = data[i];
    });
  }
});

// ── iframe detection + auto-login ──
//
// HOW AUTO-LOGIN WORKS:
// 1. iframe loads the /login page
// 2. We wait for React to render the form (poll every 200ms)
// 3. Find email + password fields using multiple selector strategies
//    so it works even if class names change after a rebuild
// 4. Fill values via the native input value setter (required for React
//    controlled inputs — a plain assignment won't trigger React's state)
// 5. Submit the form
//
// ✏️  DEMO CREDENTIALS — change these if the account changes
const DEMO_CREDENTIALS = {
  'talentscreenai': {
    email: 'judge1@talentscreen.demo',
    password: 'Judge#Demo1'
  }
  // Add more projects here if needed:
  // 'myproject': { email: '...', password: '...' }
};

document.querySelectorAll('.preview-iframe').forEach(iframe => {
  const cardId = iframe.id.replace('iframe-', '');
  const slideshow = document.getElementById('slideshow-' + cardId);
  const badge    = document.getElementById('badge-' + cardId);
  const creds    = DEMO_CREDENTIALS[cardId];

  function showSlideshow() {
    iframe.style.display = 'none';
    if (slideshow) { slideshow.style.display = 'block'; initSlideshow(cardId); }
    if (badge) { badge.textContent = 'Preview'; badge.classList.replace('live','slides'); }
  }

  // Fill a React-controlled input correctly
  // React tracks value via a synthetic event — a plain .value= won't work
  function setReactInput(el, value) {
    const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set;
    nativeInputValueSetter.call(el, value);
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
  }

  // Try to find and fill the login form inside the iframe document
  function attemptLogin(doc) {
    // Strategy 1: find by input type
    const emailField = doc.querySelector('input[type="email"], input[name="email"], input[id*="email"], input[placeholder*="email" i], input[placeholder*="Email" i]');
    const passField  = doc.querySelector('input[type="password"]');

    if (!emailField || !passField) return false; // form not ready yet

    setReactInput(emailField, creds.email);
    setReactInput(passField,  creds.password);

    // Find and click the submit button
    // Strategy: look for a button with login-related text, or a submit input
    const btn =
      doc.querySelector('button[type="submit"]') ||
      doc.querySelector('input[type="submit"]')  ||
      [...doc.querySelectorAll('button')].find(b =>
        /sign in|log in|login|continue/i.test(b.textContent)
      );

    if (btn) {
      setTimeout(() => btn.click(), 150); // tiny delay so React state settles
    } else {
      // Fallback: submit the form directly
      const form = emailField.closest('form');
      if (form) setTimeout(() => form.requestSubmit(), 150);
    }

    return true;
  }

  // Poll until the login form appears (React may take a moment to mount)
  function waitForLoginForm(doc, attempts) {
    if (attempts <= 0) { showSlideshow(); return; }
    if (!attemptLogin(doc)) {
      setTimeout(() => waitForLoginForm(doc, attempts - 1), 200);
    }
  }

  iframe.addEventListener('load', () => {
    try {
      const doc = iframe.contentDocument || iframe.contentWindow.document;

      // Blank doc = iframe was blocked
      if (!doc || !doc.body || doc.title === '') { showSlideshow(); return; }

      // If we have credentials for this project, attempt auto-login
      if (creds) {
        // Give React ~300ms to mount, then poll up to 25 times (5 seconds total)
        setTimeout(() => waitForLoginForm(doc, 25), 300);
      }
    } catch(e) {
      // Cross-origin block
      showSlideshow();
    }
  });

  // Hard fallback: if nothing happened after 12s, show slideshow
  setTimeout(() => {
    try {
      const doc = iframe.contentDocument || iframe.contentWindow.document;
      if (!doc || !doc.body || doc.body.innerHTML.trim() === '') showSlideshow();
    } catch(e) { showSlideshow(); }
  }, 12000);
});

// ── Slideshow logic ──
function initSlideshow(id) {
  const container = document.getElementById('slideshow-' + id);
  if (!container || container.dataset.initialized) return;
  container.dataset.initialized = 'true';

  const slides = container.querySelectorAll('.slide');
  const dotsContainer = document.getElementById('dots-' + id);
  let current = 0;
  let timer;

  // Build dots
  slides.forEach((_, i) => {
    const dot = document.createElement('button');
    dot.className = 'slide-dot' + (i === 0 ? ' active' : '');
    dot.setAttribute('aria-label', 'Go to slide ' + (i + 1));
    dot.addEventListener('click', () => goTo(i));
    dotsContainer.appendChild(dot);
  });

  function goTo(n) {
    slides[current].classList.remove('active');
    dotsContainer.children[current].classList.remove('active');
    current = (n + slides.length) % slides.length;
    slides[current].classList.add('active');
    dotsContainer.children[current].classList.add('active');
    resetTimer();
  }

  function resetTimer() {
    clearInterval(timer);
    timer = setInterval(() => goTo(current + 1), 3500);
  }

  container.querySelector('.prev').addEventListener('click', () => goTo(current - 1));
  container.querySelector('.next').addEventListener('click', () => goTo(current + 1));

  resetTimer();
}

// ── Hamburger menu ──
const hamburger = document.getElementById('hamburger');
const navLinks = document.getElementById('navLinks');
hamburger.addEventListener('click', () => {
  navLinks.classList.toggle('open');
});

// ── Subtle fade-in on scroll for project cards ──
const observer = new IntersectionObserver(entries => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      e.target.style.opacity = '1';
      e.target.style.transform = 'translateY(0)';
    }
  });
}, { threshold: 0.1 });

document.querySelectorAll('.project-card').forEach(card => {
  card.style.opacity = '0';
  card.style.transform = 'translateY(24px)';
  card.style.transition = 'opacity 0.5s ease, transform 0.5s ease, border-color 0.25s';
  observer.observe(card);
});
